import{_ as d,o as r,c as o,a0 as a}from"./chunks/framework.jwovEGr5.js";const b=JSON.parse('{"title":"第 1 章 初识 WorkBuddy","description":"","frontmatter":{},"headers":[],"relativePath":"p1/01.md","filePath":"p1/01.md"}'),e={name:"p1/01.md"};function s(n,t,l,h,u,i){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="第-1-章-初识-workbuddy" tabindex="-1">第 1 章 初识 WorkBuddy <a class="header-anchor" href="#第-1-章-初识-workbuddy" aria-label="Permalink to &quot;第 1 章 初识 WorkBuddy&quot;">​</a></h1><blockquote><p>本章融合了 WorkBuddy 橙皮书「第一篇：先搞懂 WorkBuddy 是什么」和蓝皮书「第 1 章 初识 WorkBuddy」的内容。</p></blockquote><p><strong>WorkBuddy</strong> 是腾讯最新推出的全场景职场 AI 智能体工作台，</p><p>面向 人力资源、行政、运营、销售、研发等不同职场角色，是一款能够像真正同事一样思考、执行任务并交付结果的 AI 办公应用。</p><h2 id="workbuddy-产品定位" tabindex="-1">WorkBuddy 产品定位 <a class="header-anchor" href="#workbuddy-产品定位" aria-label="Permalink to &quot;WorkBuddy 产品定位&quot;">​</a></h2><h3 id="它到底是什么" tabindex="-1">它到底是什么 <a class="header-anchor" href="#它到底是什么" aria-label="Permalink to &quot;它到底是什么&quot;">​</a></h3><p>WorkBuddy 是腾讯推出的<strong>全场景 AI Agent 桌面工作台</strong>。</p><p>很多人第一次听到 WorkBuddy，会下意识把它理解成&quot;又一个 AI 聊天工具&quot;。</p><p>但如果只把 WorkBuddy 当成&quot;一个能对话的 AI&quot;，你很容易低估它。</p><p>WorkBuddy 真正重要的地方，不是它能回答问题，而是它代表了 AI 助手的一次角色变化：</p><blockquote><p><strong>以前，AI 是对话框里回答你问题的人。</strong><strong>后来，AI 是在编辑器里和你一起改代码的人。</strong><strong>现在，WorkBuddy 是一个可以被交代任务的工程执行者——而且它能操作你电脑上的真实文件。</strong></p></blockquote><p>它不只是回答你&quot;这篇文章怎么写&quot;，而是可以：</p><ul><li>读取你本地的文件和项目</li><li>理解上下文和需求</li><li>制定执行计划</li><li>调用 Skill 完成专项任务</li><li>连接外部工具（MCP）扩展能力</li><li>记住你的偏好和历史</li><li>把结果直接交付到你需要的地方</li></ul><h3 id="核心能力一览" tabindex="-1">核心能力一览 <a class="header-anchor" href="#核心能力一览" aria-label="Permalink to &quot;核心能力一览&quot;">​</a></h3><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td><strong>一句话任务指派</strong></td><td>用自然语言描述需求，无需复杂操作</td></tr><tr><td><strong>自主规划与执行</strong></td><td>自动拆解任务、规划步骤、交付结果</td></tr><tr><td><strong>并行多任务</strong></td><td>同时启动和管理多个任务，通过侧边栏切换</td></tr><tr><td><strong>本地文件操作</strong></td><td>读取授权文件夹，批量处理文件</td></tr><tr><td><strong>可验证的结果</strong></td><td>生成的文档、表格、PPT 可直接使用</td></tr><tr><td><strong>Skill 扩展</strong></td><td>兼容 OpenClaw 技能生态，7万+ 社区技能</td></tr><tr><td><strong>专家系统</strong></td><td>100+ 领域专家，按需召唤</td></tr><tr><td><strong>自动化</strong></td><td>定时触发，724 小时无人值守执行</td></tr><tr><td><strong>连接器</strong></td><td>打通腾讯文档、QQ 邮箱、飞书等外部服务</td></tr></tbody></table><h3 id="三大工作模式" tabindex="-1">三大工作模式 <a class="header-anchor" href="#三大工作模式" aria-label="Permalink to &quot;三大工作模式&quot;">​</a></h3><p>WorkBuddy 的核心交互分为三个模式，覆盖不同信任程度和任务复杂度：</p><table tabindex="0"><thead><tr><th>模式</th><th>权限</th><th>行为</th><th>打个比方</th></tr></thead><tbody><tr><td><strong>Ask</strong></td><td>仅对话</td><td>只回答问题，完全不碰文件</td><td>只提建议的顾问</td></tr><tr><td><strong>Plan</strong></td><td>先读后写</td><td>先出执行计划，逐条确认后才执行</td><td>写好计划书再动手的助手</td></tr><tr><td><strong>Craft</strong></td><td>可读写 + 执行</td><td>直接操作文件、运行代码，每步仍需你确认</td><td>坐你旁边干活的搭档</td></tr></tbody></table><p><strong>使用建议</strong>：</p><ul><li>日常 90% 的任务用 <strong>Plan</strong>（先计划后执行，可控）</li><li>咨询讨论用 <strong>Ask</strong>（不需要操作文件）</li><li>批量文件处理和写代码用 <strong>Craft</strong>（效率高，但需盯紧）</li></ul><h2 id="workbuddy-与同类工具的区别" tabindex="-1">WorkBuddy 与同类工具的区别 <a class="header-anchor" href="#workbuddy-与同类工具的区别" aria-label="Permalink to &quot;WorkBuddy 与同类工具的区别&quot;">​</a></h2><h3 id="vs-chatgpt" tabindex="-1">vs ChatGPT <a class="header-anchor" href="#vs-chatgpt" aria-label="Permalink to &quot;vs ChatGPT&quot;">​</a></h3><table tabindex="0"><thead><tr><th>对比维度</th><th>ChatGPT</th><th>WorkBuddy</th></tr></thead><tbody><tr><td>主要定位</td><td>对话式 AI 助手</td><td>AI Agent 桌面工作台</td></tr><tr><td>文件操作</td><td>需手动上传/下载</td><td>直接读写本地授权文件</td></tr><tr><td>外部工具</td><td>插件/GPTs</td><td>MCP 连接器（更开放）</td></tr><tr><td>自动化</td><td>需手动触发</td><td>支持定时自动化</td></tr><tr><td>专属专家</td><td>不支持</td><td>100+ 领域专家，按需召唤</td></tr></tbody></table><p><strong>更合理的用法</strong>：用 ChatGPT 做头脑风暴、想法验证；用 WorkBuddy 执行完整的工作流和任务交付。</p><h3 id="vs-cursor-claude-code" tabindex="-1">vs Cursor / Claude Code <a class="header-anchor" href="#vs-cursor-claude-code" aria-label="Permalink to &quot;vs Cursor / Claude Code&quot;">​</a></h3><table tabindex="0"><thead><tr><th>对比维度</th><th>Cursor / Claude Code</th><th>WorkBuddy</th></tr></thead><tbody><tr><td>主要定位</td><td>AI 编辑器 / 终端 Agent</td><td>全场景桌面 Agent</td></tr><tr><td>适用场景</td><td>代码开发</td><td>办公 + 开发 + 内容创作</td></tr><tr><td>文件操作</td><td>编辑器内</td><td>本地文件系统 + 终端</td></tr><tr><td>内容创作</td><td>不支持</td><td>支持（文档、PPT、PDF）</td></tr><tr><td>专家系统</td><td>不支持</td><td>支持（可召唤领域专家）</td></tr><tr><td>自动化</td><td>不支持</td><td>支持（定时任务）</td></tr></tbody></table><p><strong>合理的用法是组合使用</strong>：用 Cursor 做日常编码；用 WorkBuddy 做跨工具全流程任务和自动化。</p><hr><p><em>（图片位置预留：WorkBuddy 主界面截图、产品架构图等。你可以在本章后面插入 <code>![](/assets/your-image.png)</code> 来添加自己的截图。）</em></p>',29)])])}const k=d(e,[["render",s]]);export{b as __pageData,k as default};
